//! τ-bowl spec ("bowlspec") — a declared, verifiable JIT-dequantization
//! admission criterion. The NEW admission dimension on top of qspec.
//!
//! Where a [`crate::qspec`] answers "does the model produce the right token?",
//! a **bowlspec** answers the orthogonal capability question:
//!
//!   "Can this model/config be JIT-dequantized — kept at COARSE-code cost
//!    (Q4/E8/Leech, masked per-op) — with a CERTIFIED ≤(1−q) quality-loss
//!    bound, distribution-free, no truth at inference?"
//!
//! It is the runtime twin of the conformal coverage cert
//! (`Gnosis.ConformalCoverageAdmissibility`): a `(speculator, step, layer)`
//! config is admitted iff the conformal threshold clears half the energy
//! margin (`2·Q_q ≤ γ`), so its serve-time lie rate is `≤ 1 − q`. The whole
//! τ-bowl is a *miss-not-lie* gate: it refuses the outlier-heavy ops rather
//! than silently degrade them.
//!
//! Verification reuses the EXISTING runtime probe — the `bowl-probe` binary in
//! `distributed-inference`, which runs the cell-filling diagnostic + Tukey-bowl
//! accept-rate (cubic vs E_8) + conformal admission on REAL admitted-knot
//! tiles (no synthetic data). The bowlspec is admitted iff the probe reports
//! `admission.admitted == true`, and — if a `min_certified_coverage` floor is
//! declared — iff every conformal row admits at coverage `q ≥ floor`. This is
//! exactly parallel to how `qspec::verify` shells out to `paris-probe-rknot`
//! and trusts its exit code: monster-guard owns the *gate*, the probe owns the
//! *measurement*. No conformal math is duplicated here.
//!
//! Contract (JSON):
//! ```json
//! { "probe": "bowl-probe",
//!   "knot": "~/.edgework/models/qwen2.5-0.5b-instruct.knot",
//!   "quality_profile": "dev-balanced",
//!   "matrix_type": "any",
//!   "q_values": [0.90, 0.95, 0.99],
//!   "gamma_multiplier": 2.0,
//!   "min_certified_coverage": 0.99 }
//! ```
//! All fields except `knot` are optional. A leading `~` in `probe`/`knot`
//! expands to `$HOME`. `min_certified_coverage`, when set, requires that every
//! coverage `q` at/above the floor be admitted (the gate's certified column).

use std::path::{Path, PathBuf};
use std::process::Command;

use serde::Deserialize;

const DEFAULT_PROBE: &str = "bowl-probe";
const DEFAULT_PROFILE: &str = "dev-balanced";
const DEFAULT_MATRIX_TYPE: &str = "any";
/// How many bytes of the probe's combined stdout/stderr tail to surface on FAIL.
const TAIL_BYTES: usize = 2048;

#[derive(Debug, Clone, Deserialize)]
pub struct BowlSpec {
    /// Probe binary name or path. Defaults to `bowl-probe`.
    #[serde(default = "default_probe")]
    pub probe: String,
    /// Path to the dense `.knot` model. A leading `~` expands to `$HOME`.
    pub knot: String,
    /// Quality profile fed to the probe: `dev-fast` | `dev-balanced` |
    /// `dev-strict`. Defaults to `dev-balanced`.
    #[serde(default = "default_profile")]
    pub quality_profile: String,
    /// Matrix-type policy: `any` | `float` | `q8_0`. Defaults to `any`.
    #[serde(default = "default_matrix_type")]
    pub matrix_type: String,
    /// Coverage levels to certify, e.g. `[0.90, 0.95, 0.99]`. When absent the
    /// probe's profile default is used.
    #[serde(default)]
    pub q_values: Option<Vec<f64>>,
    /// Energy-margin multiplier `γ = multiplier · cubic_l2_residual_scale`.
    /// When absent the probe's profile default is used.
    #[serde(default)]
    pub gamma_multiplier: Option<f64>,
    /// Optional certified-coverage FLOOR. When set, admission additionally
    /// requires that EVERY conformal row whose `q ≥ floor` be admitted at the
    /// configured γ — i.e. the model is certified JIT-dequantizable at least at
    /// this coverage. Absent ⇒ admission tracks only the probe's overall verdict.
    #[serde(default)]
    pub min_certified_coverage: Option<f64>,
}

fn default_probe() -> String {
    DEFAULT_PROBE.to_string()
}
fn default_profile() -> String {
    DEFAULT_PROFILE.to_string()
}
fn default_matrix_type() -> String {
    DEFAULT_MATRIX_TYPE.to_string()
}

/// The certified outcome of a bowlspec verification — what gets recorded as the
/// admission ledger's coverage column.
#[derive(Debug, Clone)]
pub struct BowlCertificate {
    /// The probe's overall verdict (`admission.admitted`).
    pub admitted: bool,
    /// Per-coverage certified rows: `(q, admit_at_gamma, certified_lie_rate_le)`.
    pub coverage: Vec<(f64, bool, f64)>,
    /// The best (lowest-`q`, hence widest) coverage that is certified admitted,
    /// or `None` if no row admits. The headline "certified down to coverage q".
    pub certified_at: Option<f64>,
    /// E_8/Leech wins (or ties) the energy gate vs cubic on real tiles.
    pub e8_energy_ok: bool,
}

/// Expand a leading `~` (or `~/...`) to the user's home directory.
fn expand_tilde(s: &str) -> PathBuf {
    expand_tilde_with(s, std::env::var("HOME").ok().as_deref())
}

fn expand_tilde_with(s: &str, home: Option<&str>) -> PathBuf {
    match home {
        Some(home) if s == "~" => PathBuf::from(home),
        Some(home) => match s.strip_prefix("~/") {
            Some(rest) => PathBuf::from(home).join(rest),
            None => PathBuf::from(s),
        },
        None => PathBuf::from(s),
    }
}

impl BowlSpec {
    /// Parse a bowlspec from JSON text.
    pub fn parse(text: &str) -> Result<BowlSpec, String> {
        let spec: BowlSpec =
            serde_json::from_str(text).map_err(|e| format!("invalid bowlspec JSON: {e}"))?;
        if spec.knot.trim().is_empty() {
            return Err("bowlspec: knot must not be empty".to_string());
        }
        if let Some(qs) = &spec.q_values {
            if qs.is_empty() {
                return Err("bowlspec: q_values, if present, must not be empty".to_string());
            }
            if qs.iter().any(|q| !(0.0..1.0).contains(q)) {
                return Err(
                    "bowlspec: every q_value must be a probability in (0,1) (1.0 cannot be \
                     certified — it would need an infinite calibration set)"
                        .to_string(),
                );
            }
        }
        if let Some(floor) = spec.min_certified_coverage {
            if !(0.0..1.0).contains(&floor) {
                return Err(
                    "bowlspec: min_certified_coverage must be a probability in (0,1)".to_string(),
                );
            }
        }
        Ok(spec)
    }

    /// Load + parse a bowlspec from a file.
    pub fn load(path: impl AsRef<Path>) -> Result<BowlSpec, String> {
        let path = path.as_ref();
        let text = std::fs::read_to_string(path)
            .map_err(|e| format!("could not read bowlspec '{}': {e}", path.display()))?;
        BowlSpec::parse(&text)
    }

    /// Resolve the probe to an executable path — same policy as the qspec probe:
    /// an explicit path (with `/`) is tilde-expanded and used; a bare name is
    /// taken from PATH if present, else the distributed-inference release build.
    pub fn resolve_probe(&self) -> PathBuf {
        if self.probe.contains('/') {
            return expand_tilde(&self.probe);
        }
        if which_in_path(&self.probe).is_some() {
            return PathBuf::from(&self.probe);
        }
        let manifest = env!("CARGO_MANIFEST_DIR");
        Path::new(manifest)
            .join("..")
            .join("distributed-inference")
            .join("target")
            .join("release")
            .join(&self.probe)
    }

    /// The argument vector passed to the probe (knot already tilde-expanded).
    /// Always requests JSON so the verdict can be parsed structurally.
    fn probe_args(&self) -> Vec<String> {
        let knot = expand_tilde(&self.knot);
        let mut args = vec![
            "--knot".to_string(),
            knot.to_string_lossy().into_owned(),
            "--quality-profile".to_string(),
            self.quality_profile.clone(),
            "--matrix-type".to_string(),
            self.matrix_type.clone(),
            "--format".to_string(),
            "json".to_string(),
        ];
        if let Some(qs) = &self.q_values {
            let csv = qs
                .iter()
                .map(|q| format!("{q}"))
                .collect::<Vec<_>>()
                .join(",");
            args.push("--q-values".to_string());
            args.push(csv);
        }
        if let Some(m) = self.gamma_multiplier {
            args.push("--gamma-multiplier".to_string());
            args.push(format!("{m}"));
        }
        args
    }

    /// Run the probe and parse its JSON report into a [`BowlCertificate`].
    /// Err carries the tail of the probe's combined output on a non-zero exit
    /// or an unparseable report.
    fn run_probe(&self) -> Result<BowlCertificate, String> {
        let probe = self.resolve_probe();
        let args = self.probe_args();
        let output = Command::new(&probe)
            .args(&args)
            .output()
            .map_err(|e| format!("could not run bowl-probe '{}': {e}", probe.display()))?;

        if !output.status.success() {
            let mut combined = String::new();
            combined.push_str(&String::from_utf8_lossy(&output.stdout));
            combined.push_str(&String::from_utf8_lossy(&output.stderr));
            let tail = tail_str(&combined, TAIL_BYTES);
            let code = output
                .status
                .code()
                .map(|c| c.to_string())
                .unwrap_or_else(|| "signal".to_string());
            return Err(format!("bowl-probe exited {code}; tail:\n{tail}"));
        }

        let stdout = String::from_utf8_lossy(&output.stdout);
        parse_report(&stdout)
    }

    /// Verify the bowlspec: run the probe, require its overall verdict, and (if
    /// a `min_certified_coverage` floor is set) require every coverage `q` at or
    /// above the floor to be admitted. On success returns the certificate so the
    /// caller can record the coverage column in the admission ledger.
    pub fn verify(&self) -> Result<BowlCertificate, String> {
        let cert = self.run_probe()?;

        if !cert.admitted {
            return Err(format!(
                "bowl gate FAILED: probe did not admit this knot for JIT-dequantization \
                 (admitted=false). Certified coverage rows: {}. The τ-bowl is miss-not-lie: \
                 it refuses to certify coarse-code masking it cannot bound.",
                fmt_coverage(&cert.coverage)
            ));
        }

        if let Some(floor) = self.min_certified_coverage {
            // Every coverage at/above the floor must admit. If no row reaches the
            // floor at all, the floor cannot be met either.
            let at_or_above: Vec<&(f64, bool, f64)> =
                cert.coverage.iter().filter(|(q, _, _)| *q >= floor).collect();
            if at_or_above.is_empty() {
                return Err(format!(
                    "bowl gate FAILED: no probed coverage q reaches the declared floor \
                     {floor}. Probed rows: {}.",
                    fmt_coverage(&cert.coverage)
                ));
            }
            if let Some((q, _, lie)) = at_or_above
                .iter()
                .find(|(_, admit, _)| !*admit)
                .map(|t| **t)
            {
                return Err(format!(
                    "bowl gate FAILED: coverage q={q} (certified_lie_rate_le={lie}) is NOT \
                     admitted at the configured γ, but the declared floor is \
                     min_certified_coverage={floor}. Tighten γ or lower the floor."
                ));
            }
        }

        Ok(cert)
    }
}

/// Parse the bowl-probe JSON report, extracting the admission verdict and the
/// per-coverage certified rows. Tolerant of extra fields (the probe's report is
/// rich); reads only the gate-relevant ones.
fn parse_report(text: &str) -> Result<BowlCertificate, String> {
    let v: serde_json::Value = serde_json::from_str(text.trim())
        .map_err(|e| format!("could not parse bowl-probe JSON report: {e}"))?;

    let admitted = v
        .get("admission")
        .and_then(|a| a.get("admitted"))
        .and_then(|b| b.as_bool())
        .ok_or_else(|| "bowl-probe report missing admission.admitted".to_string())?;

    let e8_energy_ok = v
        .get("admission")
        .and_then(|a| a.get("e8_energy_accept_ge_cubic"))
        .and_then(|b| b.as_bool())
        .unwrap_or(false);

    let mut coverage: Vec<(f64, bool, f64)> = Vec::new();
    if let Some(rows) = v
        .get("conformal")
        .and_then(|c| c.get("rows"))
        .and_then(|r| r.as_array())
    {
        for row in rows {
            let q = row.get("q").and_then(|x| x.as_f64());
            let admit = row.get("admit_at_gamma").and_then(|x| x.as_bool());
            let lie = row
                .get("certified_lie_rate_le")
                .and_then(|x| x.as_f64());
            if let (Some(q), Some(admit)) = (q, admit) {
                coverage.push((q, admit, lie.unwrap_or(f64::NAN)));
            }
        }
    }
    if coverage.is_empty() {
        return Err("bowl-probe report had no conformal coverage rows".to_string());
    }

    // The widest certified coverage = the lowest q that is admitted.
    let certified_at = coverage
        .iter()
        .filter(|(_, admit, _)| *admit)
        .map(|(q, _, _)| *q)
        .fold(None, |acc: Option<f64>, q| {
            Some(acc.map_or(q, |a| a.min(q)))
        });

    Ok(BowlCertificate {
        admitted,
        coverage,
        certified_at,
        e8_energy_ok,
    })
}

/// Verify a bowlspec file end to end: load, run the probe, check the gate.
pub fn verify(path: impl AsRef<Path>) -> Result<BowlCertificate, String> {
    BowlSpec::load(path)?.verify()
}

/// Render the coverage rows compactly for diagnostics / ledger lines.
pub fn fmt_coverage(coverage: &[(f64, bool, f64)]) -> String {
    coverage
        .iter()
        .map(|(q, admit, lie)| {
            format!(
                "q={q}:{}(lie≤{:.3})",
                if *admit { "MASK" } else { "recompute" },
                lie
            )
        })
        .collect::<Vec<_>>()
        .join(" ")
}

/// Last `max_bytes` of a string, on a char boundary, prefixed with `…` if cut.
fn tail_str(s: &str, max_bytes: usize) -> String {
    if s.len() <= max_bytes {
        return s.trim_end().to_string();
    }
    let mut start = s.len() - max_bytes;
    while start < s.len() && !s.is_char_boundary(start) {
        start += 1;
    }
    format!("…{}", s[start..].trim_end())
}

/// Minimal PATH lookup: is `name` an executable somewhere on `$PATH`?
fn which_in_path(name: &str) -> Option<PathBuf> {
    let path = std::env::var_os("PATH")?;
    for dir in std::env::split_paths(&path) {
        let candidate = dir.join(name);
        if is_executable(&candidate) {
            return Some(candidate);
        }
    }
    None
}

fn is_executable(p: &Path) -> bool {
    use std::os::unix::fs::PermissionsExt;
    p.metadata()
        .map(|m| m.is_file() && (m.permissions().mode() & 0o111) != 0)
        .unwrap_or(false)
}

#[cfg(test)]
mod tests {
    use super::*;

    // ---- pure parser unit tests (no probe needed) -------------------------

    #[test]
    fn parses_full_bowlspec() {
        let spec = BowlSpec::parse(
            r#"{ "probe": "bowl-probe",
                 "knot": "~/.edgework/models/qwen2.5-0.5b-instruct.knot",
                 "quality_profile": "dev-strict",
                 "matrix_type": "q8_0",
                 "q_values": [0.95, 0.99],
                 "gamma_multiplier": 1.6,
                 "min_certified_coverage": 0.99 }"#,
        )
        .unwrap();
        assert_eq!(spec.probe, "bowl-probe");
        assert_eq!(spec.quality_profile, "dev-strict");
        assert_eq!(spec.matrix_type, "q8_0");
        assert_eq!(spec.q_values, Some(vec![0.95, 0.99]));
        assert_eq!(spec.gamma_multiplier, Some(1.6));
        assert_eq!(spec.min_certified_coverage, Some(0.99));
    }

    #[test]
    fn defaults_when_minimal() {
        let spec = BowlSpec::parse(r#"{ "knot": "/tmp/x.knot" }"#).unwrap();
        assert_eq!(spec.probe, DEFAULT_PROBE);
        assert_eq!(spec.quality_profile, DEFAULT_PROFILE);
        assert_eq!(spec.matrix_type, DEFAULT_MATRIX_TYPE);
        assert!(spec.q_values.is_none());
        assert!(spec.gamma_multiplier.is_none());
        assert!(spec.min_certified_coverage.is_none());
    }

    #[test]
    fn empty_knot_rejected() {
        let err = BowlSpec::parse(r#"{ "knot": "  " }"#).unwrap_err();
        assert!(err.contains("knot"), "got: {err}");
    }

    #[test]
    fn q_value_of_one_rejected() {
        let err = BowlSpec::parse(r#"{ "knot": "/x", "q_values": [0.9, 1.0] }"#).unwrap_err();
        assert!(err.contains("probability"), "got: {err}");
    }

    #[test]
    fn empty_q_values_rejected() {
        let err = BowlSpec::parse(r#"{ "knot": "/x", "q_values": [] }"#).unwrap_err();
        assert!(err.contains("q_values"), "got: {err}");
    }

    #[test]
    fn out_of_range_floor_rejected() {
        let err =
            BowlSpec::parse(r#"{ "knot": "/x", "min_certified_coverage": 1.0 }"#).unwrap_err();
        assert!(err.contains("min_certified_coverage"), "got: {err}");
    }

    #[test]
    fn malformed_json_rejected() {
        assert!(BowlSpec::parse("{ not json").is_err());
    }

    #[test]
    fn tilde_expansion_uses_home() {
        let home = Some("/home/zzz");
        assert_eq!(
            expand_tilde_with("~/.edgework/models/a.knot", home),
            PathBuf::from("/home/zzz/.edgework/models/a.knot")
        );
        assert_eq!(expand_tilde_with("~", home), PathBuf::from("/home/zzz"));
        assert_eq!(
            expand_tilde_with("/abs/path", home),
            PathBuf::from("/abs/path")
        );
    }

    #[test]
    fn probe_args_carry_json_and_overrides() {
        let spec = BowlSpec::parse(
            r#"{ "knot": "/tmp/x.knot", "quality_profile": "dev-strict",
                 "matrix_type": "q8_0", "q_values": [0.95, 0.99],
                 "gamma_multiplier": 1.6 }"#,
        )
        .unwrap();
        let args = spec.probe_args();
        assert!(args
            .windows(2)
            .any(|w| w[0] == "--format" && w[1] == "json"));
        assert!(args
            .windows(2)
            .any(|w| w[0] == "--quality-profile" && w[1] == "dev-strict"));
        assert!(args
            .windows(2)
            .any(|w| w[0] == "--matrix-type" && w[1] == "q8_0"));
        assert!(args
            .windows(2)
            .any(|w| w[0] == "--q-values" && w[1] == "0.95,0.99"));
        assert!(args
            .windows(2)
            .any(|w| w[0] == "--gamma-multiplier" && w[1] == "1.6"));
    }

    // ---- report parsing (pure; mirrors bowl-probe's JSON shape) -----------

    fn sample_report(admitted: bool, rows: &str) -> String {
        format!(
            r#"{{
              "tool": "bowl-probe",
              "admission": {{ "admitted": {admitted},
                             "e8_energy_accept_ge_cubic": true }},
              "conformal": {{ "train_rows": 100, "test_rows": 100, "rows": [{rows}] }}
            }}"#
        )
    }

    #[test]
    fn parses_admitted_report_with_coverage() {
        let rows = r#"
          {"q":0.90,"admit_at_gamma":true,"certified_lie_rate_le":0.10},
          {"q":0.95,"admit_at_gamma":true,"certified_lie_rate_le":0.05},
          {"q":0.99,"admit_at_gamma":false,"certified_lie_rate_le":0.01}
        "#;
        let cert = parse_report(&sample_report(true, rows)).unwrap();
        assert!(cert.admitted);
        assert!(cert.e8_energy_ok);
        assert_eq!(cert.coverage.len(), 3);
        // widest certified coverage = lowest admitted q = 0.90
        assert_eq!(cert.certified_at, Some(0.90));
    }

    #[test]
    fn report_without_rows_is_an_error() {
        let err = parse_report(&sample_report(true, "")).unwrap_err();
        assert!(err.contains("coverage rows"), "got: {err}");
    }

    #[test]
    fn verify_logic_floor_met() {
        // A spec with a 0.95 floor against a report admitting 0.90 and 0.95.
        let rows = r#"
          {"q":0.90,"admit_at_gamma":true,"certified_lie_rate_le":0.10},
          {"q":0.95,"admit_at_gamma":true,"certified_lie_rate_le":0.05}
        "#;
        let cert = parse_report(&sample_report(true, rows)).unwrap();
        // Re-run the floor logic directly (verify() needs the probe binary).
        let floor = 0.95f64;
        let at_or_above: Vec<_> =
            cert.coverage.iter().filter(|(q, _, _)| *q >= floor).collect();
        assert!(!at_or_above.is_empty());
        assert!(at_or_above.iter().all(|(_, admit, _)| *admit));
    }

    #[test]
    fn verify_logic_floor_violated() {
        // 0.99 is probed but NOT admitted; a 0.99 floor must fail.
        let rows = r#"
          {"q":0.95,"admit_at_gamma":true,"certified_lie_rate_le":0.05},
          {"q":0.99,"admit_at_gamma":false,"certified_lie_rate_le":0.01}
        "#;
        let cert = parse_report(&sample_report(true, rows)).unwrap();
        let floor = 0.99f64;
        let violated = cert
            .coverage
            .iter()
            .filter(|(q, _, _)| *q >= floor)
            .any(|(_, admit, _)| !*admit);
        assert!(violated, "0.99 floor should be violated by a non-admitted 0.99 row");
    }

    #[test]
    fn fmt_coverage_is_readable() {
        let s = fmt_coverage(&[(0.9, true, 0.1), (0.99, false, 0.01)]);
        assert!(s.contains("q=0.9:MASK"));
        assert!(s.contains("q=0.99:recompute"));
    }
}
